 41→export function PostCard({
 42→  title,
 43→  bodyPreview,
 44→  authorName,
 45→  authorAvatar,
 46→  authorBadge,
 47→  bannerImage,
 48→  postType,
 49→  readingTime,
 50→  likeCount,
