 1→import {
 2→    createCanvasRemixService
 3→} from "../services/canvasService.js";
 4→
 5→export const createCanvasRemixController = async(req, res) => {
 6→    const userId = req.userId;
 7→    const {sourceJournalId, titleOverride} = req.body;
 8→
 9→    try {
10→        const remix = await createCanvasRemixService({
11→            sourceJournalId: sourceJournalId,
12→            userId: userId,
13→            titleOverride: titleOverride
14→        });
